namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _messages =
    [
        "Your order has been shipped",
        "New comment on your post",
        "System maintenance scheduled",
        "Welcome to the platform!",
        "Your report is ready to download",
        "Password changed successfully",
        "New follower added",
        "Payment received",
        "Subscription renewal reminder",
        "Security alert: new login detected"
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        var items = Enumerable.Range(0, 3).Select(_ => CreateNotification()).ToList();
        return Task.FromResult(items);
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        // Simulate ~30% chance of a new notification each poll
        if (Random.Shared.Next(100) < 30)
        {
            return Task.FromResult(new List<NotificationItem> { CreateNotification() });
        }

        return Task.FromResult(new List<NotificationItem>());
    }

    private NotificationItem CreateNotification()
    {
        return new NotificationItem
        {
            Id = _nextId++,
            Message = _messages[Random.Shared.Next(_messages.Length)],
            Timestamp = DateTime.Now
        };
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch data that was persisted from the prerender pass
        notifications ??= await NotificationSvc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newItems = await NotificationSvc.CheckForNewNotificationsAsync();
            if (newItems.Count > 0)
            {
                notifications ??= [];
                notifications.InsertRange(0, newItems);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

