@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
    }
</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else if (notifications.Count == 0)
{
    <p>No notifications.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? notifications { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we don't re-fetch data that was persisted from the prerender pass
        notifications ??= await NotificationSvc.GetInitialNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            var newItems = await NotificationSvc.CheckForNewNotificationsAsync();
            if (newItems.Count > 0)
            {
                notifications ??= [];
                notifications.InsertRange(0, newItems);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

