namespace NotificationsApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly string[] _messages =
    [
        "Your order has been shipped",
        "New comment on your post",
        "System maintenance scheduled",
        "Welcome to the platform!",
        "Your report is ready to download",
        "Password changed successfully",
        "New follower added",
        "Payment received",
        "Subscription renewal reminder",
        "Security alert: new login detected"
    ];

    public Task<List<NotificationItem>> GetInitialNotificationsAsync()
    {
        var items = Enumerable.Range(0, 3).Select(_ => CreateNotification()).ToList();
        return Task.FromResult(items);
    }

    public Task<List<NotificationItem>> CheckForNewNotificationsAsync()
    {
        // ~30% chance of a new notification each poll
        if (Random.Shared.Next(100) < 30)
        {
            return Task.FromResult(new List<NotificationItem> { CreateNotification() });
        }

        return Task.FromResult(new List<NotificationItem>());
    }

    private NotificationItem CreateNotification()
    {
        return new NotificationItem
        {
            Id = _nextId++,
            Message = _messages[Random.Shared.Next(_messages.Length)],
            Timestamp = DateTime.Now
        };
    }
}

